tests:
def test_empty_search():
    t = BTree()
    assert t.search(5) is None

def test_multiple_inserts():
    t = BTree(min_degree=3)
    items = [(5, 'a'), (3, 'b'), (8, 'c'), (1, 'd'), (15, 'e'), (12, 'f')]
    for k, v in items:
        t.insert(k, v)
    for k, v in items:
        assert t.search(k) == v

def test_split_increases_height():
    t = BTree(min_degree=2)
    for k in range(1, 10):
        t.insert(k, str(k))
    assert t.height() >= 2

def test_range_query_empty():
    t = BTree()
    for k in [10, 20, 30]:
        t.insert(k, str(k))
    result = t.range_query(50, 100)
    assert result == []

def test_many_inserts():
    t = BTree(min_degree=3)
    for k in range(100):
        t.insert(k, k * 2)
    for k in range(100):
        assert t.search(k) == k * 2
    assert t.size() == 100

def test_range_after_inserts():
    t = BTree(min_degree=3)
    for k in range(50):
        t.insert(k, k)
    result = t.range_query(10, 20)
    assert [k for k, v in result] == list(range(10, 21))
